function extractUrls(text) {
  const t = String(text || "");
  const matches = t.match(/https?:\/\/[^\s<>()]+/gi) || [];
  return matches.map((u) => u.replace(/[\]\[),.?!;:'\"]+$/g, ""));
}

function detectPlatform(url) {
  try {
    const u = new URL(url);
    const host = u.hostname.toLowerCase();

    const isTikTok =
      host === "tiktok.com" ||
      host.endsWith(".tiktok.com") ||
      host === "vm.tiktok.com";

    const isX =
      host === "x.com" ||
      host.endsWith(".x.com") ||
      host === "twitter.com" ||
      host.endsWith(".twitter.com") ||
      host === "t.co";

    if (isTikTok) return "tiktok";
    if (isX) return "x";
    return "";
  } catch {
    return "";
  }
}

export function extractFirstSupportedUrl(text) {
  const urls = extractUrls(text);
  if (!urls.length) return null;

  let ignoredCount = 0;

  for (let i = 0; i < urls.length; i++) {
    const url = urls[i];
    const platform = detectPlatform(url);
    if (platform) {
      ignoredCount = Math.max(0, urls.length - (i + 1));
      return { url, platform, ignoredCount };
    }
  }

  return null;
}

downloader.js.content:
import { safeErr } from "../lib/safeErr.js";
import { resolveRedirects } from "../lib/http.js";
import { resolveTikTokMedia } from "./tiktok.js";
import { resolveXMedia } from "./x.js";

function detect(url) {
  try {
    const u = new URL(url);
    const h = u.hostname.toLowerCase();
    if (h === "tiktok.com" || h.endsWith(".tiktok.com") || h === "vm.tiktok.com") return "tiktok";
    if (h === "x.com" || h.endsWith(".x.com") || h === "twitter.com" || h.endsWith(".twitter.com") || h === "t.co") return "x";
    return "";
  } catch {
    return "";
  }
}

export async function downloadFromUrl(inputUrl, { platformHint = "", status = async () => {} } = {}) {
  const originalUrl = String(inputUrl || "");

  await status("Resolving redirects…");
  const normalizedUrl = await resolveRedirects(originalUrl);

  const platform = platformHint || detect(normalizedUrl) || detect(originalUrl);
  if (!platform) {
    const e = new Error("UNSUPPORTED_URL");
    e.code = "UNSUPPORTED_URL";
    throw e;
  }

  console.log("[downloader] detected", { platform, originalUrl, normalizedUrl });

  try {
    await status("Extracting media…");
    if (platform === "tiktok") {
      return await resolveTikTokMedia(normalizedUrl);
    }
    if (platform === "x") {
      return await resolveXMedia(normalizedUrl);
    }
    const e = new Error("UNSUPPORTED_URL");
    e.code = "UNSUPPORTED_URL";
    throw e;
  } catch (e) {
    const msg = safeErr(e);
    console.error("[downloader] resolve failed", { platform, normalizedUrl, err: msg });
    throw e;
  }
}

telegramSender.js.content:
import { InputFile } from "grammy";
import { safeErr } from "../lib/safeErr.js";
import { downloadToBuffer } from "../lib/http.js";

export async function editStatusSafe(ctx, chatId, messageId, text) {
  if (!chatId || !messageId) return;
  try {
    await ctx.api.editMessageText(Number(chatId), Number(messageId), text);
  } catch (e) {
    // ignore; message may be gone
    console.warn("[tg] editMessageText failed", { err: safeErr(e) });
  }
}

export async function setStatusSafe(ctx, chatId, messageId, text) {
  // same as edit, but throttled could be added later
  return editStatusSafe(ctx, chatId, messageId, text);
}

async function sendVideoWithFallback(ctx, chatId, buffer, filename, caption, sourceUrl) {
  try {
    console.log("[tg] sendVideo", { chatId });
    await ctx.api.sendVideo(Number(chatId), new InputFile(buffer, filename), {
      caption,
    });
    return;
  } catch (e) {
    console.warn("[tg] sendVideo failed, fallback to sendDocument", {
      err: safeErr(e),
    });
  }

  try {
    console.log("[tg] sendDocument", { chatId });
    await ctx.api.sendDocument(Number(chatId), new InputFile(buffer, filename), {
      caption,
    });
  } catch (e) {
    console.error("[tg] sendDocument failed", { err: safeErr(e) });
    await ctx.api.sendMessage(
      Number(chatId),
      "I downloaded the media but Telegram rejected the upload. Here is the source link:\n" +
        String(sourceUrl)
    );
  }
}

async function sendPhotoWithFallback(ctx, chatId, buffer, filename, caption, urlFallback) {
  try {
    console.log("[tg] sendPhoto", { chatId });
    await ctx.api.sendPhoto(Number(chatId), new InputFile(buffer, filename), {
      caption,
    });
    return;
  } catch (e) {
    console.warn("[tg] sendPhoto failed", { err: safeErr(e) });
  }

  if (urlFallback) {
    try {
      console.log("[tg] sendPhoto by URL", { chatId });
      await ctx.api.sendPhoto(Number(chatId), urlFallback, { caption });
      return;
    } catch (e) {
      console.warn("[tg] sendPhoto by URL failed", { err: safeErr(e) });
    }
  }

  try {
    console.log("[tg] sendDocument (image fallback)", { chatId });
    await ctx.api.sendDocument(Number(chatId), new InputFile(buffer, filename), {
      caption,
    });
  } catch (e) {
    console.error("[tg] sendDocument (image) failed", { err: safeErr(e) });
    await ctx.api.sendMessage(
      Number(chatId),
      "I couldn’t upload the image. Here is the source link:\n" + String(urlFallback || "")
    );
  }
}

export async function sendMediaResultToTelegram(ctx, { chatId, sourceUrl, result }) {
  const caption = "Source: " + String(sourceUrl);

  if (!result || !result.kind || !Array.isArray(result.items) || !result.items.length) {
    throw new Error("NO_MEDIA");
  }

  if (result.kind === "video") {
    const item = result.items[0];
    const { buffer } = await downloadToBuffer(item.url);
    await sendVideoWithFallback(ctx, chatId, buffer, "video.mp4", caption, sourceUrl);
    return;
  }

  // Images: try media group first if >1
  if (result.kind === "images") {
    if (result.items.length > 1) {
      try {
        console.log("[tg] sendMediaGroup", { chatId, count: result.items.length });
        const media = [];
        for (let i = 0; i < result.items.length; i++) {
          const it = result.items[i];
          const { buffer } = await downloadToBuffer(it.url);
          media.push({
            type: "photo",
            media: new InputFile(buffer, `image-${i + 1}.jpg`),
            caption: i === 0 ? caption : undefined,
          });
        }
        await ctx.api.sendMediaGroup(Number(chatId), media);
        return;
      } catch (e) {
        console.warn("[tg] sendMediaGroup failed, fallback to sequential", {
          err: safeErr(e),
        });
      }
    }

    for (let i = 0; i < result.items.length; i++) {
      const it = result.items[i];
      const { buffer } = await downloadToBuffer(it.url);
      const cap = i === 0 ? caption : "Source: " + String(sourceUrl);
      await sendPhotoWithFallback(ctx, chatId, buffer, `image-${i + 1}.jpg`, cap, it.url);
    }
    return;
  }

  throw new Error("UNSUPPORTED_MEDIA_KIND");
}

tiktok.js.content:
import { fetchWithRetries } from "../lib/http.js";

function extractJsonFromHtml(html) {
  const s = String(html || "");

  // Try SIGI_STATE (common)
  const sigi = s.match(/<script[^>]*id="SIGI_STATE"[^>]*>([\s\S]*?)<\/script>/i);
  if (sigi && sigi[1]) {
    try {
      return JSON.parse(sigi[1]);
    } catch {}
  }

  // Try __UNIVERSAL_DATA_FOR_REHYDRATION__
  const uni = s.match(/<script[^>]*id="__UNIVERSAL_DATA_FOR_REHYDRATION__"[^>]*>([\s\S]*?)<\/script>/i);
  if (uni && uni[1]) {
    try {
      return JSON.parse(uni[1]);
    } catch {}
  }

  return null;
}

function pickBestVideoUrl(obj) {
  // Heuristics over known TikTok shapes
  // Return a direct mp4 URL if available.
  const candidates = [];

  try {
    const itemModule = obj?.ItemModule || obj?.itemModule;
    if (itemModule && typeof itemModule === "object") {
      const firstKey = Object.keys(itemModule)[0];
      const item = itemModule[firstKey];
      const play = item?.video?.playAddr;
      const download = item?.video?.downloadAddr;
      const bitRates = item?.video?.bitrateInfo;
      if (Array.isArray(bitRates)) {
        for (const b of bitRates) {
          const u = b?.PlayAddr?.UrlList?.[0] || b?.PlayAddr?.UrlList?.[1];
          if (u) candidates.push(String(u));
        }
      }
      if (play) candidates.push(String(play));
      if (download) candidates.push(String(download));

      const images = item?.imagePost?.images;
      if (Array.isArray(images) && images.length) {
        const imageUrls = images
          .map((im) => im?.imageURL?.urlList?.[0] || im?.imageURL?.urlList?.[1])
          .filter(Boolean)
          .map(String);
        if (imageUrls.length) {
          return { type: "images", urls: imageUrls };
        }
      }
    }
  } catch {}

  const uniq = Array.from(new Set(candidates.filter(Boolean)));
  if (uniq.length) return { type: "video", urls: uniq };
  return null;
}

export async function resolveTikTokMedia(url) {
  const u = String(url || "");

  const res = await fetchWithRetries(u, {
    method: "GET",
    headers: {
      Accept: "text/html,application/xhtml+xml",
    },
  });

  if (!res.ok) {
    if (res.status === 401 || res.status === 403 || res.status === 404) {
      const e = new Error("Public content only");
      e.code = "PUBLIC_ONLY";
      throw e;
    }
    throw new Error(`TIKTOK_HTTP_${res.status}`);
  }

  const html = await res.text();
  const json = extractJsonFromHtml(html);
  if (!json) {
    // TikTok may block scraping or require JS; treat as public-only restriction.
    const e = new Error("Public content only");
    e.code = "PUBLIC_ONLY";
    throw e;
  }

  const picked = pickBestVideoUrl(json);
  if (!picked) {
    const e = new Error("Public content only");
    e.code = "PUBLIC_ONLY";
    throw e;
  }

  if (picked.type === "images") {
    return {
      platform: "tiktok",
      kind: "images",
      items: picked.urls.map((x) => ({ url: x, mime: "image/jpeg" })),
    };
  }

  return {
    platform: "tiktok",
    kind: "video",
    items: [{ url: picked.urls[0], mime: "video/mp4" }],
  };
}

x.js.content:
import { fetchWithRetries } from "../lib/http.js";

function extractOgImage(html) {
  const m = String(html || "").match(
    /<meta[^>]+property="og:image"[^>]+content="([^"]+)"/i
  );
  if (m && m[1]) return m[1];
  return "";
}

function extractOgVideo(html) {
  const m = String(html || "").match(
    /<meta[^>]+property="og:video"[^>]+content="([^"]+)"/i
  );
  if (m && m[1]) return m[1];
  return "";
}

export async function resolveXMedia(url) {
  const u = String(url || "");

  const res = await fetchWithRetries(u, {
    method: "GET",
    headers: {
      Accept: "text/html,application/xhtml+xml",
    },
  });

  if (!res.ok) {
    if (res.status === 401 || res.status === 403 || res.status === 404) {
      const e = new Error("Public content only");
      e.code = "PUBLIC_ONLY";
      throw e;
    }
    throw new Error(`X_HTTP_${res.status}`);
  }

  const html = await res.text();

  // Lightweight approach: rely on OpenGraph. For many tweets with video,
  // og:video is not a direct mp4, but sometimes it is.
  const ogVideo = extractOgVideo(html);
  if (ogVideo) {
    return {
      platform: "x",
      kind: "video",
      items: [{ url: ogVideo, mime: "video/mp4" }],
    };
  }

  const ogImage = extractOgImage(html);
  if (ogImage) {
    return {
      platform: "x",
      kind: "images",
      items: [{ url: ogImage, mime: "image/jpeg" }],
    };
  }

  const e = new Error("Public content only");
  e.code = "PUBLIC_ONLY";
  throw e;
}
